changeSet.sql:
CREATE TYPE VariableFunction as ENUM ('MAX', 'MIN', 'ABS', 'NONE');
CREATE TYPE VariableOperation as ENUM ('PLUS', 'MINUS', 'MULTIPLY', 'DIVIDE', 'OPEN_BRACKET', 'CLOSE_BRACKET', 'NONE');
CREATE TYPE ValueSource as ENUM ('PROCESS_REVENUE', 'SYSTEM_NUMBER_OF_REC', 'VALUE');

CREATE TABLE metric_variables
(
	id serial,
	quant_metric_id integer DEFAULT NULL,
	ordinal integer DEFAULT 0,
	name character varying (127) NOT NULL,
	description text,
	factor float DEFAULT NULL,
	value float DEFAULT NULL,
	operation_before VariableOperation DEFAULT NULL,
	operation_after VariableOperation DEFAULT NULL,
	value_source ValueSource DEFAULT NULL,
	variable_function VariableFunction DEFAULT NULL,
	CONSTRAINT pk_metric_variables PRIMARY KEY (id)
	, CONSTRAINT fk_metric_variables_to_quant_metric FOREIGN KEY (quant_metric_id) REFERENCES quant_metrics (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_metric_variables_quant_metric ON metric_variables (quant_metric_id);
CREATE UNIQUE INDEX ui_metric_variables_quant_metric_ordinal ON metric_variables (quant_metric_id, ordinal);
